import ts from"typescript";export const isNotJS=t=>!isJS(t);export const isJS=t=>t.scriptKind===ts.ScriptKind.JS||t.scriptKind===ts.ScriptKind.JSX;export const isModule=t=>ts.isExternalModule(t);export function hasImportSpecifier(t,i,e){return ts.isImportDeclaration(t)&&ts.isStringLiteral(t.moduleSpecifier)&&t.moduleSpecifier.text===i&&!!t.importClause?.namedBindings&&ts.isNamedImports(t.importClause.namedBindings)&&(!e||t.importClause.namedBindings.elements.some(t=>t.name.text===e))}